function areNumbersIncreasing(s) {
    const tokens = s.split(" ");
    const numbers = [];

    for (const token of tokens) {
        if (!isNaN(token)) {
            const num = parseInt(token);
            if (numbers.length && numbers[numbers.length - 1] >= num) {
                return false;
            }
            numbers.push(num);
        }
    }

    return true;
}
