import java.util.*;

public boolean areNumbersIncreasing(String s) {
    Scanner scanner = new Scanner(s);
    ArrayList<Integer> numbers = new ArrayList<>();

    while (scanner.hasNext()) {
        if (scanner.hasNextInt()) {
            int num = scanner.nextInt();
            if (!numbers.isEmpty() && numbers.get(numbers.size() - 1) >= num) {
                return false;
            }
            numbers.add(num);
        } else {
            scanner.next();
        }
    }

    return true;
}
```

